function KpiCard({ label, value, sub, color, pct=60 }) {
  return (
    <div style={{
      background:"#161b22", border:"1px solid #30363d", borderRadius:10,
      padding:"14px 16px", position:"relative", overflow:"hidden"
    }}>
      <div style={{fontSize:10,color:"#94a3b8",letterSpacing:".06em",marginBottom:5,fontFamily:"monospace",textTransform:"uppercase"}}>{label}</div>
      <div style={{fontSize:26,fontWeight:900,fontFamily:"monospace",color,lineHeight:1}}>{value}</div>
      {sub && <div style={{fontSize:11,color:"#64748b",marginTop:4}}>{sub}</div>}
      <div style={{height:2,background:"rgba(255,255,255,.06)",borderRadius:1,marginTop:10}}>
        <div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:1,transition:"width 1s ease"}}/>
      </div>
    </div>
  );
}

function AlertBadge({ level }) {
  const cfg = { danger:{bg:"rgba(244,63,94,.1)",border:"rgba(244,63,94,.3)",color:"#f43f5e"},
                warn: {bg:"rgba(251,191,36,.1)",border:"rgba(251,191,36,.3)",color:"#fbbf24"},
                ok:   {bg:"rgba(74,222,128,.1)",border:"rgba(74,222,128,.3)",color:"#4ade80"} };
  const s = cfg[level]||cfg.ok;
  return <div style={{display:"inline-block",background:s.bg,border:`1px solid ${s.border}`,
    color:s.color,fontSize:10,fontFamily:"monospace",fontWeight:700,borderRadius:4,padding:"2px 7px"}}>{level.toUpperCase()}</div>;
}

function ProgressBar({ label, value, max, color="#22d3ee", unit="" }) {
  const pct = Math.min(100, (value/max)*100);
  return (
    <div style={{marginBottom:8}}>
      <div style={{display:"flex",justifyContent:"space-between",fontSize:11,marginBottom:3}}>
        <span style={{color:"#c9d1d9"}}>{label}</span>
        <span style={{fontFamily:"monospace",color}}>{fmt(value)}{unit}</span>
      </div>
      <div style={{height:6,background:"rgba(255,255,255,.06)",borderRadius:3,overflow:"hidden"}}>
        <div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:3,transition:"width 1s ease"}}/>
      </div>
    </div>
  );
}

